import { Component, computed } from '@angular/core';
import { CommonModule } from '@angular/common';
import { RouterLink } from '@angular/router';
import { SeedService } from '../../../data/seed.service';
import { AuthService } from '../../../core/services/auth.service';
import { Order } from '../../../data/models';

@Component({
  selector: 'app-portal-orders',
  standalone: true,
  imports: [CommonModule, RouterLink],
  templateUrl: './portal-orders.component.html',
  styleUrl: './portal-orders.component.css',
})
export class PortalOrdersComponent {
  // STRICT company scoping — QES orders only.
  orders = computed<Order[]>(() =>
    this.seed.orders().filter((o) => o.accountName.includes('QES')),
  );

  totalOpen = computed(() => this.orders().filter((o) => o.status !== 'delivered').length);
  onTime = computed(() => this.orders().filter((o) => !o.slippage).length);
  delayed = computed(() => this.orders().filter((o) => o.slippage).length);

  constructor(public seed: SeedService, public auth: AuthService) {}

  statusBadge(status: Order['status']): string {
    switch (status) {
      case 'confirmed': return 'badge-info';
      case 'in-production': return 'badge-warning';
      case 'shipped': return 'badge-success';
      case 'delivered': return 'badge-neutral';
      default: return 'badge-neutral';
    }
  }

  deliveryBadge(o: Order): { cls: string; label: string } {
    return o.slippage
      ? { cls: 'badge-warning', label: `Delayed ${o.slippageDays}d` }
      : { cls: 'badge-success', label: 'On time' };
  }
}
